__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"DISCLAIMER",{enumerable:!0,get:function(){return s}}),Object.defineProperty(e,"LEGAL",{enumerable:!0,get:function(){return t}}),Object.defineProperty(e,"PRIVACY_POLICY",{enumerable:!0,get:function(){return n}}),Object.defineProperty(e,"TERMS_OF_USE",{enumerable:!0,get:function(){return o}});const s="Kyroz est con\xe7u pour des adultes en bonne sant\xe9. Ces informations ne remplacent pas l'avis d'un m\xe9decin ou di\xe9t\xe9ticien-nutritionniste.",t={appName:'Kyroz',controllerName:'K\xe9vin Berger',controllerStatus:'Entrepreneur individuel (micro-entreprise)',siren:'[\xc0 COMPL\xc9TER \u2014 n\xb0 SIREN \xe0 9 chiffres]',address:'2 rue du moulin, 64570 Arette',dpoEmail:'dpo@kyroz.app',supportEmail:'support@kyroz.app',host:'Supabase Inc.',hostRegion:'Union europ\xe9enne (UE)',effectiveDate:'15 juin 2026'},n=[{title:'1. Responsable de traitement',paragraphs:[`Le responsable du traitement de vos donn\xe9es est ${t.controllerName}, ${t.controllerStatus}, SIREN ${t.siren}, ${t.address}.`,`Pour toute question relative \xe0 vos donn\xe9es ou pour exercer vos droits : ${t.dpoEmail}.`]},{title:'2. Donn\xe9es collect\xe9es',paragraphs:["Donn\xe9es de compte : adresse email (lors d\u2019une inscription par email).","Donn\xe9es de sant\xe9 : sexe, \xe2ge, poids, taille, taux de masse grasse, niveau d\u2019activit\xe9 et sport pratiqu\xe9, objectif, restrictions et pr\xe9f\xe9rences alimentaires. Ces informations sont des donn\xe9es de sant\xe9 au sens de l\u2019article 9 du RGPD.","Donn\xe9es d\u2019usage de l\u2019app : plans g\xe9n\xe9r\xe9s, suivi du poids, s\xe9rie (streak), favoris, garde-manger.","Photos de progression (facultatives) : elles restent stock\xe9es UNIQUEMENT sur votre appareil et ne sont jamais transmises \xe0 nos serveurs."]},{title:'3. Finalit\xe9s',paragraphs:["Vos donn\xe9es servent exclusivement \xe0 : calculer vos besoins nutritionnels (calories, macros), g\xe9n\xe9rer vos plans repas, votre liste de courses et le suivi associ\xe9.","Aucune donn\xe9e n\u2019est utilis\xe9e \xe0 des fins publicitaires."]},{title:'4. Base l\xe9gale',paragraphs:["Le traitement des donn\xe9es de sant\xe9 repose sur votre consentement explicite (RGPD art. 9-2-a), recueilli \xe0 l\u2019inscription. Vous pouvez le retirer \xe0 tout moment en supprimant votre compte."]},{title:'5. Destinataires et sous-traitants',paragraphs:[`Vos donn\xe9es synchronis\xe9es sont h\xe9berg\xe9es par ${t.host}, sur des serveurs situ\xe9s en ${t.hostRegion}.`,"Nous ne vendons, ne louons et ne partageons vos donn\xe9es avec aucun tiers \xe0 des fins commerciales. Aucun traceur publicitaire ni outil d\u2019analyse tiers n\u2019est utilis\xe9."]},{title:'6. H\xe9bergement et localisation',paragraphs:["Les donn\xe9es synchronis\xe9es sont stock\xe9es dans l\u2019Union europ\xe9enne. Une copie de travail r\xe9side localement sur votre appareil (fonctionnement hors-ligne)."]},{title:'7. Dur\xe9e de conservation',paragraphs:["Vos donn\xe9es sont conserv\xe9es tant que votre compte est actif. Elles sont supprim\xe9es d\xe9finitivement (serveur + appareil) lorsque vous supprimez votre compte."]},{title:'8. S\xe9curit\xe9',paragraphs:["Les \xe9changes avec nos serveurs sont chiffr\xe9s en transit (HTTPS). L\u2019acc\xe8s aux donn\xe9es est cloisonn\xe9 par utilisateur : un utilisateur ne peut acc\xe9der qu\u2019\xe0 ses propres donn\xe9es.","Les donn\xe9es stock\xe9es localement sur votre appareil ne sont pas chiffr\xe9es : prot\xe9gez l\u2019acc\xe8s \xe0 votre appareil, en particulier sur un ordinateur partag\xe9."]},{title:'9. Vos droits',paragraphs:["Conform\xe9ment au RGPD, vous disposez des droits d\u2019acc\xe8s, de rectification, d\u2019effacement, de limitation, d\u2019opposition et de portabilit\xe9, ainsi que du droit de retirer votre consentement.",`Le droit \xe0 l\u2019effacement s\u2019exerce directement dans l\u2019app (Profil \u2192 Supprimer mon compte) ou par email \xe0 ${t.dpoEmail}.`,"Vous pouvez introduire une r\xe9clamation aupr\xe8s de la CNIL (www.cnil.fr)."]},{title:'10. Mineurs',paragraphs:["Kyroz est r\xe9serv\xe9 aux personnes \xe2g\xe9es de 16 ans et plus. Aucun compte ne peut \xeatre cr\xe9\xe9 en de\xe7\xe0 de cet \xe2ge."]},{title:'11. Modifications',paragraphs:[`La pr\xe9sente politique peut \xe9voluer. Date de derni\xe8re mise \xe0 jour : ${t.effectiveDate}.`]}],o=[{title:'1. Objet',paragraphs:[`Les pr\xe9sentes conditions r\xe9gissent l\u2019utilisation de l\u2019application ${t.appName}. En cr\xe9ant un compte ou en utilisant l\u2019app, vous les acceptez.`]},{title:'2. Description du service',paragraphs:["Kyroz g\xe9n\xe8re des plans repas, des listes de courses et des recettes \xe0 vis\xe9e nutritionnelle, \xe0 partir des informations que vous fournissez. Le c\u0153ur du service est gratuit."]},{title:'3. Avertissement sant\xe9',paragraphs:[s,"Kyroz ne s\u2019adresse pas aux personnes atteintes de pathologies (diab\xe8te, insuffisance r\xe9nale, troubles cardiaques\u2026), aux femmes enceintes ou allaitantes. En cas de doute, consultez un professionnel de sant\xe9. Vous restez seul responsable de votre alimentation."]},{title:'4. Compte',paragraphs:["Vous vous engagez \xe0 fournir des informations exactes et \xe0 avoir au moins 16 ans. Vous \xeates responsable de la confidentialit\xe9 de vos identifiants."]},{title:'5. Propri\xe9t\xe9 intellectuelle',paragraphs:["Les recettes et contenus de l\u2019app sont la propri\xe9t\xe9 de Kyroz. Les donn\xe9es nutritionnelles sont issues de la table Ciqual (ANSES), r\xe9utilis\xe9es sous Licence Ouverte 2.0 (Etalab)."]},{title:'6. Donn\xe9es personnelles',paragraphs:["Le traitement de vos donn\xe9es est d\xe9crit dans la Politique de confidentialit\xe9 ci-dessus, qui fait partie int\xe9grante des pr\xe9sentes conditions."]},{title:'7. R\xe9siliation',paragraphs:["Vous pouvez supprimer votre compte \xe0 tout moment depuis l\u2019app (Profil \u2192 Supprimer mon compte), ce qui efface d\xe9finitivement vos donn\xe9es."]},{title:'8. Responsabilit\xe9',paragraphs:["Kyroz fournit un outil d\u2019aide \xe0 la planification nutritionnelle sans garantie de r\xe9sultat. Notre responsabilit\xe9 ne saurait \xeatre engag\xe9e pour l\u2019usage que vous faites des plans propos\xe9s."]},{title:'9. Droit applicable',paragraphs:[`Les pr\xe9sentes conditions sont soumises au droit fran\xe7ais. Contact : ${t.supportEmail}. En cas de litige, vous pouvez recourir \xe0 un m\xe9diateur de la consommation ou saisir la CNIL pour les questions relatives aux donn\xe9es.`]}]},929,[]);
